INSERT INTO products (id, title, description, price, original_price, rating, rating_count, image, category, brand, vertical, is_assured, delivery_time, specs) VALUES ('s1', 'iPhone 15 Pro (128 GB) - Natural Titanium', 'iPhone 15 Pro has a strong and light aerospace-grade titanium design with a textured matte-glass back. It also features a Ceramic Shield front that is tougher than any smartphone glass.', 127999, 134900, 4.7, 14500, 'https://images.unsplash.com/photo-1695048133142-1a20484d2569?w=600&auto=format&fit=crop&q=60', 's-mobiles', 'Apple', 'shop', true, 'Delivery by Tomorrow, 10 AM', '{"Display":"6.1-inch Super Retina XDR OLED","Processor":"A17 Pro Chip with 6-core GPU","Camera":"48MP Main + 12MP Ultra Wide + 12MP 3x Telephoto","Battery":"Up to 23 hours video playback","Weight":"187g"}') ON CONFLICT (id) DO UPDATE SET title=EXCLUDED.title, price=EXCLUDED.price;
